import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';

function Problem() {
  const { id } = useParams();
  const [problem, setProblem] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    async function fetchProblem() {
      setLoading(true);
      setError(null);
      try {
        const response = await axios.get(`/api/problems/${id}`); // Adjust API path as needed
        setProblem(response.data);
      } catch (err) {
        setError(err.response?.data?.message || 'Failed to fetch problem.');
      } finally {
        setLoading(false);
      }
    }
    fetchProblem();
  }, [id]);

  if (loading) return <p>Loading problem details...</p>;
  if (error) return <p style={{ color: 'red' }}>Error: {error}</p>;
  if (!problem) return <p>No problem found.</p>;

  return (
    <div>
      <h1>{problem.title}</h1>
      <p><strong>Category:</strong> {problem.category}</p>
      <p><strong>Difficulty:</strong> {problem.difficulty}</p>
      <p><strong>Description:</strong></p>
      <p>{problem.description}</p>
    </div>
  );
}

export default Problem;
